module top_module(
    input [1:0] src1,
    input [1:0] src2,
    input [1:0] dst,
    input [7:0] ip,
    input clk,
    input rst,
    input we,
    output [7:0] op1,
    output [7:0] op2
    );reg [7:0] mem_cells [3:0];

			always @ (posedge clk) begin
			if (rst==1) 
			begin	

						mem_cells[0] = 0;
						mem_cells[1] = 0;
						mem_cells[2] = 0;
						mem_cells[3] = 0;

		end 

		else if (we == 1) begin 

			mem_cells[dst] = ip;

		end

	end

	assign op1 = mem_cells[src1];

	assign op2 = mem_cells[src2];

endmodule
